import { olka, createSignal, createEffect } from "../core";
import Button from "./Button";
export default () => {
	let [todos, setTodos] = createSignal([
		"todo 1",
		"todo 2",
		"todo 3",
		"todo 4",
		"todo 5",
	]),
		[counter, setCounter] = createSignal(0),
		[newTodo, setNewTodo] = createSignal("");
	return (
		createEffect(() => {
			console.log("Todos:", todos());
		}),
		olka.createElement(
			"div",
			null,
			olka.createElement("input", {
				type: "text",
				value: newTodo(),
				onInput: (e) => {
					setNewTodo(e.target.value),
						setCounter(e.target.value);
				},
			}),
			olka.createElement(
				"button",
				{
					onClick: () => {
						setTodos((prevState) => [
							...prevState(),
							newTodo(),
						]),
							setNewTodo("");
					},
				},
				"Add Todo"
			),
			olka.createElement(
				"ul",
				null,
				todos().map((todo, index) =>
					olka.createElement(
						olka.wrapper,
						null,
						olka.createElement(
							"div",
							null,
							counter,
							olka.createElement(
								"li",
								{ key: index },
								todo
							)
						),
						olka.createElement(
							Button,
							null,
							"Click Me!"
						)
					)
				)
			),
			olka.createElement(
				"ol",
				null,
				olka.createElement(
					"li",
					null,
					olka.createElement(
						"a",
						{
							target: "_blank",
							href: "google.com",
						},
						olka.createElement(
							"span",
							null,
							"Hey Howdy1"
						)
					)
				),
				olka.createElement(
					"li",
					null,
					olka.createElement(
						"a",
						{
							target: "_blank",
							href: "google.com",
						},
						olka.createElement(
							"span",
							null,
							"Hey Howdy2"
						)
					)
				),
				olka.createElement(
					"li",
					null,
					olka.createElement(
						"a",
						{
							target: "_blank",
							href: "google.com",
						},
						olka.createElement(
							"span",
							null,
							"Hey Howdy3"
						)
					)
				)
			)
		)
	);
};
